head.script:
//==================================================================================================================
// id       : sl_101_01_08p 
// 이름     : 재고관리번호조회
// 경로     : 물류/작업실적/CFS/
// 작 성 자 : 조성빈
// 작 업 일 : 2026-01-02
// 사용계정 : 내부
// 비고     :  ***
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//==================================================================================================================
scwin.onpageload = function() {

	// String CodeList = "^ ," + GauceUtil.getCodeList("OP120");
    scwin.cvsslMgntNo = $c.data.getParameter("cvsslMgntNo") == null ? "" : $c.data.getParameter("cvsslMgntNo");  // 본선관리번호
    scwin.lobranCd    = $c.data.getMemInfo("lobranCd");
    scwin.lobranNm    = $c.data.getMemInfo("lobranNm"); 
    scwin.sDate       = $c.date.getServerDateTime("yyyyMMdd");  
    scwin.nowDt       = $c.date.getServerDateTime("yyyyMMdd");
    scwin.vQryStDt    = scwin.nowDt.substring(0, 4) + "0101";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
    scwin.vQryEndDt   = scwin.nowDt.substring(0, 6) + $c.date.getLastDateOfMonth(scwin.nowDt);  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)
    scwin.vMonStDt    = scwin.nowDt.substring(0, 6) + "01";  // 

    $c.data.setPopupTitle($c.data.getParameter("paramTitle"));	
    scwin.args = $p.getAllParameter().paramData.data;
    scwin.cvsslMgntNo = scwin.args[0].trim();
    scwin.impExpClsCd = scwin.args[1];
    scwin.stockMgntNo = "";
    if (typeof(scwin.args[2]) != "undefined"  ){
        scwin.stockMgntNo = scwin.args[2].trim();
    }

    const codeOptions = [
        { grpCd : "SL005", compID : "gr_stock:strRateStsCd" }
    ];
    $c.data.setCommonCode(codeOptions, scwin.setCommonCodeCallBack);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

    }, {"delay":50});
};

scwin.setCommonCodeCallBack = function(){
	ica_arvStDt.setValue("20150101");
	ica_arvEndDt.setValue(scwin.vQryEndDt);
	ica_wrkStDt.setValue(scwin.vMonStDt);
	ica_wrkEndDt.setValue(scwin.nowDt);
	$c.gus.cfDisableObjects([ed_clntNo,ed_clntNm,ed_commCd,ed_commNm]);

	scwin.f_Retrieve();

};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------      
scwin.f_Retrieve = async function () {
  	if (!await $c.gus.cfValidate([tbl_condition])) {	 
  		return;
	} 
	if (scwin.stockMgntNo != ""){
		ds_condition.set("stockMgntNo", scwin.stockMgntNo);
	}
    $c.sbm.execute(sbm_search);

};


//-------------------------------------------------------------------------
// 휴지통
//-------------------------------------------------------------------------  
scwin.f_FieldClear = function () {
	$c.gus.cfInitObjects(tbl_condition, null);
	ica_arvStDt.focus();
};

