scwin.f_clntClsCd = function(data, formattData, rowIdx, colIdx){
    if (data == "2"){
        return "농협/축협"
    } else if (data == "1"){
        return "사협"
    } else {
        return "개별"
    }
};

scwin.f_stockWt = function(data, formattData, rowIdx, colIdx){
    if (data < 0){
        gr_stock.setCellBackgroundColor(rowIdx, colIdx, "pink");
    }
    return data;
};
